 11→void test_scaffold() {
 12→    /* Fixnum */
 13→    puts_str("fixnum 42 = ");
 14→    print_val(MAKE_FIXNUM(42));
 15→    putc_uart(10);
 16→
 17→    /* Symbols */
 18→    puts_str("nil = ");
 19→    print_val(NIL_VAL);
 20→    putc_uart(10);
 21→
 22→    puts_str("t = ");
 23→    print_val(T_VAL);
 24→    putc_uart(10);
 25→
 26→    int foo = intern("foo");
 27→    puts_str("foo = ");
 28→    print_val(foo);
 29→    putc_uart(10);
 30→
 31→    /* Cons pair */
 32→    int pair = cons(MAKE_FIXNUM(1), MAKE_FIXNUM(2));
 33→    puts_str("(1 . 2) = ");
 34→    print_val(pair);
 35→    putc_uart(10);
 36→
 37→    /* List (a b c) */
 38→    int sa = intern("a");
 39→    int sb = intern("b");
 40→    int sc = intern("c");
 41→    int lst = cons(sa, cons(sb, cons(sc, NIL_VAL)));
 42→    puts_str("(a b c) = ");
 43→    print_val(lst);
 44→    putc_uart(10);
 45→
 46→    /* Nested list (1 (2 3)) */
 47→    int inner = cons(MAKE_FIXNUM(2), cons(MAKE_FIXNUM(3), NIL_VAL));
 48→    int nested = cons(MAKE_FIXNUM(1), cons(inner, NIL_VAL));
 49→    puts_str("(1 (2 3)) = ");
 50→    print_val(nested);
 51→    putc_uart(10);
 52→
 53→    puts_str("scaffold ok\n");
 54→}
 55→
 56→void test_read_one(char *input, char *expected) {
 57→    int val = read_str(input);
 58→    puts_str(input);
 59→    puts_str(" => ");
 60→    print_val(val);
 61→    puts_str(" [");
 62→    puts_str(expected);
 63→    puts_str("]\n");
 64→}
 65→
 66→void test_reader() {
 67→    /* Integers */
 68→    test_read_one("42", "42");
 69→    test_read_one("-7", "-7");
 70→    test_read_one("0", "0");
 71→
 72→    /* Symbols */
 73→    test_read_one("foo", "foo");
 74→    test_read_one("nil", "nil");
 75→    test_read_one("+", "+");
 76→
 77→    /* Empty list */
 78→    test_read_one("()", "nil");
 79→
 80→    /* Simple list */
 81→    test_read_one("(1 2 3)", "(1 2 3)");
 82→
 83→    /* Dotted pair */
 84→    test_read_one("(1 . 2)", "(1 . 2)");
 85→
 86→    /* Nested list */
 87→    test_read_one("(a (b c))", "(a (b c))");
 88→
 89→    /* Quote */
 90→    test_read_one("'x", "(quote x)");
 91→
 92→    /* Mixed */
 93→    test_read_one("(+ 1 2)", "(+ 1 2)");
 94→    test_read_one("(define x 42)", "(define x 42)");
 95→
 96→    puts_str("reader ok\n");
 97→}
