 99→void test_eval_one(char *input, char *expected) {
100→    int expr = read_str(input);
101→    int result = eval(expr, NIL_VAL);
102→    puts_str(input);
103→    puts_str(" => ");
104→    print_val(result);
105→    puts_str(" [");
106→    puts_str(expected);
107→    puts_str("]\n");
108→}
109→
110→void test_eval() {
111→    /* Self-evaluating */
112→    test_eval_one("42", "42");
113→    test_eval_one("-7", "-7");
114→
115→    /* Quote */
116→    test_eval_one("(quote foo)", "foo");
117→    test_eval_one("'(1 2 3)", "(1 2 3)");
118→
119→    /* Arithmetic */
120→    test_eval_one("(+ 1 2)", "3");
121→    test_eval_one("(- 10 3)", "7");
122→    test_eval_one("(* 4 5)", "20");
123→    test_eval_one("(/ 10 3)", "3");
124→
125→    /* Nested arithmetic */
126→    test_eval_one("(+ (* 2 3) (- 10 4))", "12");
127→
128→    /* Comparison */
129→    test_eval_one("(< 1 2)", "t");
130→    test_eval_one("(< 2 1)", "nil");
131→    test_eval_one("(= 5 5)", "t");
132→    test_eval_one("(= 5 6)", "nil");
133→
134→    /* If */
135→    test_eval_one("(if t 1 2)", "1");
136→    test_eval_one("(if nil 1 2)", "2");
137→    test_eval_one("(if (< 1 2) 10 20)", "10");
138→
139→    /* List operations */
140→    test_eval_one("(cons 1 2)", "(1 . 2)");
141→    test_eval_one("(car (cons 1 2))", "1");
142→    test_eval_one("(cdr (cons 1 2))", "2");
143→    test_eval_one("(list 1 2 3)", "(1 2 3)");
144→
145→    /* Predicates */
146→    test_eval_one("(null? nil)", "t");
147→    test_eval_one("(null? 1)", "nil");
148→    test_eval_one("(pair? (cons 1 2))", "t");
149→    test_eval_one("(atom? 42)", "t");
150→    test_eval_one("(not nil)", "t");
151→    test_eval_one("(not t)", "nil");
152→
153→    /* Lambda */
154→    test_eval_one("((lambda (x) (+ x 1)) 41)", "42");
155→    test_eval_one("((lambda (x y) (+ x y)) 3 4)", "7");
156→
157→    /* Begin */
158→    test_eval_one("(begin 1 2 3)", "3");
159→
160→    /* Define and use */
161→    eval(read_str("(define x 42)"), NIL_VAL);
162→    test_eval_one("x", "42");
163→
164→    eval(read_str("(define double (lambda (n) (* n 2)))"), NIL_VAL);
165→    test_eval_one("(double 21)", "42");
166→
167→    /* Higher-order */
168→    eval(read_str("(define apply-twice (lambda (f x) (f (f x))))"), NIL_VAL);
169→    test_eval_one("(apply-twice double 5)", "20");
170→
171→    /* Closure */
172→    eval(read_str("(define make-adder (lambda (n) (lambda (x) (+ n x))))"), NIL_VAL);
173→    eval(read_str("(define add5 (make-adder 5))"), NIL_VAL);
174→    test_eval_one("(add5 10)", "15");
175→
176→    /* Recursion */
177→    eval(read_str("(define fact (lambda (n) (if (= n 0) 1 (* n (fact (- n 1))))))"), NIL_VAL);
178→    test_eval_one("(fact 5)", "120");
179→
180→    puts_str("eval ok\n");
181→}
182→
183→int main() {
184→    heap_init();
185→    symbol_init();
186→    eval_init();
187→    test_scaffold();
188→    test_reader();
189→    test_eval();
190→    return 0;
191→}
