 3→/* heap.h -- Cell heap with bump allocator
 4→ * Parallel arrays instead of struct array (simpler codegen for tc24r)
 5→ */
 6→
 7→int heap_car[HEAP_SIZE];
 8→int heap_cdr[HEAP_SIZE];
 9→int heap_next;
10→
11→void heap_init() {
12→    heap_next = 0;
13→}
14→
15→int alloc_cell() {
16→    if (heap_next >= HEAP_SIZE) {
17→        puts_str("OOM\n");
18→        asm("_oom_halt:");
19→        asm("bra _oom_halt");
20→    }
21→    int idx = heap_next;
22→    heap_next = heap_next + 1;
23→    heap_car[idx] = NIL_VAL;
24→    heap_cdr[idx] = NIL_VAL;
25→    return idx;
26→}
27→
28→int cons(int a, int d) {
29→    int idx = alloc_cell();
30→    heap_car[idx] = a;
31→    heap_cdr[idx] = d;
32→    return MAKE_CONS(idx);
33→}
34→
35→int car(int v) { return heap_car[PTR_IDX(v)]; }
36→int cdr(int v) { return heap_cdr[PTR_IDX(v)]; }
37→

 1→#pragma once
 2→
 3→/* symbol.h -- Symbol interning */
 4→
 5→#define MAX_SYMBOLS 256
 6→#define NAME_POOL_SIZE 2048
 7→
 8→char name_pool[NAME_POOL_SIZE];
 9→int name_pool_next;
10→
11→int sym_name_off[MAX_SYMBOLS];
12→int sym_count;
13→
14→int str_eq(char *a, char *b) {
15→    while (*a && *b && *a == *b) {
16→        a = a + 1;
17→        b = b + 1;
18→    }
19→    return *a == *b;
20→}
21→
22→int str_len(char *s) {
23→    int n = 0;
24→    while (*s) { n = n + 1; s = s + 1; }
25→    return n;
26→}
27→
28→void str_copy(char *dst, char *src) {
29→    while (*src) {
30→        *dst = *src;
31→        dst = dst + 1;
32→        src = src + 1;
33→    }
34→    *dst = 0;
35→}
36→
37→char *sym_name(int sym) {
38→    int idx = PTR_IDX(sym);
39→    return &name_pool[sym_name_off[idx]];
40→}
41→
42→int intern(char *name) {
43→    int i = 0;
44→    while (i < sym_count) {
45→        if (str_eq(&name_pool[sym_name_off[i]], name)) {
46→            return MAKE_SYMBOL(i);
47→        }
48→        i = i + 1;
49→    }
50→    if (sym_count >= MAX_SYMBOLS) {
51→        puts_str("SYM\n");
52→        asm("_sym_halt:");
53→        asm("bra _sym_halt");
54→    }
55→    int len = str_len(name);
56→    if (name_pool_next + len + 1 > NAME_POOL_SIZE) {
57→        puts_str("SYM2\n");
58→        asm("_sym2_halt:");
59→        asm("bra _sym2_halt");
60→    }
61→    int idx = sym_count;
62→    sym_name_off[idx] = name_pool_next;
63→    str_copy(&name_pool[name_pool_next], name);
64→    name_pool_next = name_pool_next + len + 1;
65→    sym_count = sym_count + 1;
66→    return MAKE_SYMBOL(idx);
67→}
68→
69→void symbol_init() {
70→    name_pool_next = 0;
71→    sym_count = 0;
72→    intern("nil");
73→    intern("t");
74→}
