  3→/* read.h -- S-expression reader
  4→ *
  5→ * Reads from a char* input string. Handles:
  6→ *   - Integers (positive and negative)
  7→ *   - Symbols (interned)
  8→ *   - Lists: (a b c), dotted pairs: (a . b)
  9→ *   - Quote shorthand: 'x -> (quote x)
 10→ */
 11→
 12→char *read_ptr;
 13→
 14→int is_whitespace(int ch) {
 15→    return ch == ' ' || ch == '\n' || ch == '\t' || ch == '\r';
 16→}
 17→
 18→int is_digit(int ch) {
 19→    return ch >= '0' && ch <= '9';
 20→}
 21→
 22→int is_sym_char(int ch) {
 23→    if (ch == 0) return 0;
 24→    if (is_whitespace(ch)) return 0;
 25→    if (ch == '(' || ch == ')' || ch == '\'') return 0;
 26→    if (ch == '.') return 0;
 27→    return 1;
 28→}
 29→
 30→void skip_whitespace() {
 31→    while (is_whitespace(*read_ptr)) {
 32→        read_ptr = read_ptr + 1;
 33→    }
 34→}
 35→
 36→int read_expr();
 37→
 38→int read_int() {
 39→    int neg = 0;
 40→    if (*read_ptr == '-') {
 41→        neg = 1;
 42→        read_ptr = read_ptr + 1;
 43→    }
 44→    int n = 0;
 45→    while (is_digit(*read_ptr)) {
 46→        n = n * 10 + (*read_ptr - '0');
 47→        read_ptr = read_ptr + 1;
 48→    }
 49→    if (neg) n = 0 - n;
 50→    return MAKE_FIXNUM(n);
 51→}
 52→
 53→int read_symbol() {
 54→    char buf[64];
 55→    int i = 0;
 56→    while (is_sym_char(*read_ptr) && i < 63) {
 57→        buf[i] = *read_ptr;
 58→        i = i + 1;
 59→        read_ptr = read_ptr + 1;
 60→    }
 61→    buf[i] = 0;
 62→    return intern(buf);
 63→}
 64→
 65→int read_list() {
 66→    /* skip opening '(' */
 67→    read_ptr = read_ptr + 1;
 68→    skip_whitespace();
 69→
 70→    if (*read_ptr == ')') {
 71→        read_ptr = read_ptr + 1;
 72→        return NIL_VAL;
 73→    }
 74→
 75→    /* read first element */
 76→    int first = read_expr();
 77→    skip_whitespace();
 78→
 79→    /* check for dotted pair */
 80→    if (*read_ptr == '.') {
 81→        read_ptr = read_ptr + 1;
 82→        skip_whitespace();
 83→        int d = read_expr();
 84→        skip_whitespace();
 85→        if (*read_ptr == ')') {
 86→            read_ptr = read_ptr + 1;
 87→        }
 88→        return cons(first, d);
 89→    }
 90→
 91→    /* build list */
 92→    int head = cons(first, NIL_VAL);
 93→    int tail = head;
 94→    while (*read_ptr && *read_ptr != ')') {
 95→        int elem = read_expr();
 96→        skip_whitespace();
 97→
 98→        /* check for dot after element */
 99→        if (*read_ptr == '.') {
100→            read_ptr = read_ptr + 1;
101→            skip_whitespace();
102→            int d = read_expr();
103→            skip_whitespace();
104→            heap_cdr[PTR_IDX(tail)] = d;
105→            if (*read_ptr == ')') {
106→                read_ptr = read_ptr + 1;
107→            }
108→            return head;
109→        }
110→
111→        int cell = cons(elem, NIL_VAL);
112→        heap_cdr[PTR_IDX(tail)] = cell;
113→        tail = cell;
114→    }
115→
116→    if (*read_ptr == ')') {
117→        read_ptr = read_ptr + 1;
118→    }
119→    return head;
120→}
121→
122→int read_expr() {
123→    skip_whitespace();
124→
125→    int ch = *read_ptr;
126→
127→    if (ch == '(') {
128→        return read_list();
129→    }
130→
131→    if (ch == '\'') {
132→        read_ptr = read_ptr + 1;
133→        int val = read_expr();
134→        int quote_sym = intern("quote");
135→        return cons(quote_sym, cons(val, NIL_VAL));
136→    }
137→
138→    /* negative number: '-' followed by digit */
139→    if (ch == '-' && is_digit(*(read_ptr + 1))) {
140→        return read_int();
141→    }
142→
143→    if (is_digit(ch)) {
144→        return read_int();
145→    }
146→
147→    /* symbol */
148→    if (ch != 0 && ch != ')') {
149→        return read_symbol();
150→    }
151→
152→    return NIL_VAL;
153→}
154→
155→int read_str(char *input) {
156→    read_ptr = input;
157→    return read_expr();
158→}
