  3→/* gc.h -- Mark-sweep garbage collector
  4→ *
  5→ * Cells are allocated from a free list. When the free list is empty,
  6→ * GC marks all reachable cells from roots, then sweeps unmarked cells
  7→ * back onto the free list.
  8→ *
  9→ * Roots: global_env, pre-interned symbols, and the explicit root stack
 10→ * (for protecting temporaries across allocations).
 11→ */
 12→
 13→#define MAX_GC_ROOTS 64
 14→
 15→int heap_mark[HEAP_SIZE];
 16→int free_list;      /* head of free list (cell index), -1 = empty */
 17→int gc_roots[MAX_GC_ROOTS];
 18→int gc_root_count;
 19→int gc_collections;  /* statistics */
 20→
 21→void gc_init() {
 22→    free_list = -1;
 23→    gc_root_count = 0;
 24→    gc_collections = 0;
 25→}
 26→
 27→/* --- Root stack for protecting temporaries --- */
 28→
 29→int gc_protect(int val) {
 30→    if (gc_root_count >= MAX_GC_ROOTS) {
 31→        puts_str("GC:roots\n");
 32→        asm("_gcr_halt:");
 33→        asm("bra _gcr_halt");
 34→    }
 35→    gc_roots[gc_root_count] = val;
 36→    gc_root_count = gc_root_count + 1;
 37→    return val;
 38→}
 39→
 40→void gc_unprotect(int n) {
 41→    gc_root_count = gc_root_count - n;
 42→}
 43→
 44→/* --- Mark phase --- */
 45→
 46→void gc_mark_val(int v) {
 47→    /* Only cons and extended values reference heap cells */
 48→    if (IS_CONS(v)) {
 49→        int idx = PTR_IDX(v);
 50→        if (heap_mark[idx]) return;  /* already marked */
 51→        heap_mark[idx] = 1;
 52→        gc_mark_val(heap_car[idx]);
 53→        gc_mark_val(heap_cdr[idx]);
 54→    } else if (IS_EXTENDED(v)) {
 55→        int idx = PTR_IDX(v);
 56→        if (heap_mark[idx]) return;
 57→        heap_mark[idx] = 1;
 58→        /* Extended objects store type in car, data in cdr.
 59→         * Data may reference other heap cells (closures, macros). */
 60→        gc_mark_val(heap_car[idx]);
 61→        gc_mark_val(heap_cdr[idx]);
 62→    }
 63→}
 64→
 65→/* --- Sweep phase --- */
 66→
 67→void gc_sweep() {
 68→    free_list = -1;
 69→    int i = heap_next - 1;
 70→    while (i >= 0) {
 71→        if (heap_mark[i]) {
 72→            heap_mark[i] = 0;  /* clear for next cycle */
 73→        } else {
 74→            /* Add to free list */
 75→            heap_cdr[i] = free_list;
 76→            heap_car[i] = NIL_VAL;  /* clear for safety */
 77→            free_list = i;
 78→        }
 79→        i = i - 1;
 80→    }
 81→}
 82→
 83→/* --- Collect --- */
 84→
 85→void gc_collect() {
 86→    gc_collections = gc_collections + 1;
 87→
 88→    /* Clear marks */
 89→    int i = 0;
 90→    while (i < heap_next) {
 91→        heap_mark[i] = 0;
 92→        i = i + 1;
 93→    }
 94→
 95→    /* Mark from global environment */
 96→    gc_mark_val(global_env);
 97→
 98→    /* Mark pre-interned special form symbols' values
 99→     * (symbols themselves are not heap-allocated, but their
100→     *  bindings in global_env are already covered above) */
101→
102→    /* Mark root stack */
103→    i = 0;
104→    while (i < gc_root_count) {
105→        gc_mark_val(gc_roots[i]);
106→        i = i + 1;
107→    }
108→
109→    /* Sweep */
110→    gc_sweep();
111→}
112→
113→/* --- Allocation with GC --- */
114→
115→int gc_alloc_cell() {
116→    /* Try free list first */
117→    if (free_list >= 0) {
118→        int idx = free_list;
119→        free_list = heap_cdr[idx];
120→        heap_car[idx] = NIL_VAL;
121→        heap_cdr[idx] = NIL_VAL;
122→        return idx;
123→    }
124→
125→    /* Try bump allocator */
126→    if (heap_next < HEAP_SIZE) {
127→        int idx = heap_next;
128→        heap_next = heap_next + 1;
129→        heap_car[idx] = NIL_VAL;
130→        heap_cdr[idx] = NIL_VAL;
131→        return idx;
132→    }
133→
134→    /* Out of space: collect and retry free list */
135→    gc_collect();
136→
137→    if (free_list >= 0) {
138→        int idx = free_list;
139→        free_list = heap_cdr[idx];
140→        heap_car[idx] = NIL_VAL;
141→        heap_cdr[idx] = NIL_VAL;
142→        return idx;
143→    }
144→
145→    /* Truly out of memory */
146→    puts_str("OOM\n");
147→    asm("_oom2_halt:");
148→    asm("bra _oom2_halt");
149→    return 0;
150→}
