 1→//! tc24r -- Tiny C compiler targeting the COR24 ISA.
 2→
 3→use std::path::Path;
 4→use std::process;
 5→
 6→fn main() {
 7→    let args: Vec<String> = std::env::args().collect();
 8→
 9→    if args.len() < 2 {
10→        eprintln!("usage: tc24r <input.c> [-o output.s] [-I dir]");
11→        process::exit(1);
12→    }
13→
14→    let input_path = &args[1];
15→    let source = read_source(input_path);
16→    let source_dir = Path::new(input_path).parent();
17→    let include_dirs = collect_include_dirs(&args);
18→    let output = compile(&source, source_dir, &include_dirs);
19→    write_output(&args, &output);
20→}
21→
22→fn read_source(path: &str) -> String {
23→    match std::fs::read_to_string(path) {
24→        Ok(s) => s,
25→        Err(e) => {
26→            eprintln!("tc24r: cannot read {path}: {e}");
27→            process::exit(1);
28→        }
29→    }
30→}
31→
32→fn collect_include_dirs(args: &[String]) -> Vec<String> {
33→    args.windows(2)
34→        .filter(|w| w[0] == "-I")
35→        .map(|w| w[1].clone())
36→        .collect()
37→}
38→
39→fn compile(source: &str, source_dir: Option<&Path>, include_dirs: &[String]) -> String {
40→    let sys_paths: Vec<&Path> = include_dirs.iter().map(|s| Path::new(s.as_str())).collect();
41→    let preprocessed = tc24r_preprocess::preprocess(source, source_dir, &sys_paths);
42→    let tokens = match tc24r_lexer::Lexer::new(&preprocessed).tokenize() {
43→        Ok(t) => t,
44→        Err(e) => {
45→            eprintln!("tc24r: {e}");
46→            process::exit(1);
47→        }
48→    };
49→
50→    let program = match tc24r_parser::parse(tokens) {
51→        Ok(p) => p,
52→        Err(e) => {
53→            eprintln!("tc24r: {e}");
54→            process::exit(1);
55→        }
56→    };
57→
58→    tc24r_codegen::Codegen::new().generate(&program)
59→}
60→
61→fn write_output(args: &[String], output: &str) {
62→    let output_path = args
63→        .windows(2)
64→        .find(|w| w[0] == "-o")
65→        .map(|w| w[1].as_str());
66→
67→    match output_path {
68→        Some(path) => {
69→            if let Err(e) = std::fs::write(path, output) {
70→                eprintln!("tc24r: cannot write {path}: {e}");
71→                process::exit(1);
72→            }
73→        }
74→        None => print!("{output}"),
75→    }
76→}
