  1→//! EmulatorCore: shared emulator controller for CLI and Web UI
  2→//!
  3→//! Provides run_batch(), pause/resume, breakpoints, and I/O accessors.
  4→//! Both the CLI debugger and Yew/WASM UI call this directly (no IPC).
  5→
  6→use crate::cpu::executor::{ExecuteResult, Executor};
  7→use crate::cpu::instruction::{DecodedInstruction, Opcode};
  8→use crate::cpu::state::{CpuState, DecodeRom};
  9→use crate::loader;
 10→
 11→/// Why a batch stopped
 12→#[derive(Debug, Clone, PartialEq, Eq)]
 13→pub enum StopReason {
 14→    /// Ran the requested number of instructions
 15→    CycleLimit,
 16→    /// Hit a breakpoint at this address
 17→    Breakpoint(u32),
 18→    /// CPU halted (executed halt sentinel)
 19→    Halted,
 20→    /// Invalid instruction encountered
 21→    InvalidInstruction(u8),
 22→    /// Emulator is paused (pause was requested)
 23→    Paused,
 24→}
 25→
 26→/// Result of a run_batch call
 27→#[derive(Debug, Clone)]
 28→pub struct BatchResult {
 29→    /// Number of instructions executed in this batch
 30→    pub instructions_run: u64,
 31→    /// Why execution stopped
 32→    pub reason: StopReason,
 33→    /// Number of new UART output bytes since batch started
 34→    pub uart_bytes_added: usize,
 35→    /// Whether LED state changed during batch
 36→    pub led_changed: bool,
 37→}
 38→
 39→/// Snapshot of CPU state for UI display
 40→#[derive(Debug, Clone)]
 41→pub struct CpuSnapshot {
 42→    pub regs: [u32; 8],
 43→    pub pc: u32,
 44→    pub c: bool,
 45→    pub halted: bool,
 46→    pub intis: bool,
 47→    pub cycles: u64,
 48→    pub instructions: u64,
 49→    pub led: u8,
 50→    pub button: u8,
 51→    pub uart_output_len: usize,
 52→}
 53→
 54→/// The shared emulator core
 55→#[derive(Clone)]
 56→pub struct EmulatorCore {
 57→    cpu: CpuState,
 58→    executor: Executor,
 59→    decode_rom: DecodeRom,
 60→    breakpoints: Vec<u32>,
 61→    paused: bool,
 62→    /// Highest address written during load (tracks end of code+data)
 63→    program_end: u32,
 64→}
 65→
 66→impl Default for EmulatorCore {
 67→    fn default() -> Self {
 68→        Self::new()
 69→    }
 70→}
 71→
 72→impl EmulatorCore {
 73→    pub fn new() -> Self {
 74→        Self {
 75→            cpu: CpuState::new(),
 76→            executor: Executor::new(),
 77→            decode_rom: DecodeRom::new(),
 78→            breakpoints: Vec::new(),
 79→            paused: true, // start paused
 80→            program_end: 0,
 81→        }
 82→    }
 83→
 84→    // ===== Load =====
 85→
 86→    /// Load an LGO file into memory, set entry point
 87→    pub fn load_lgo(&mut self, content: &str, entry: Option<u32>) -> Result<usize, String> {
 88→        self.cpu = CpuState::new();
 89→        let result = loader::load_lgo(content, &mut self.cpu)?;
 90→        let start = entry.or(result.start_addr).unwrap_or(0);
 91→        self.cpu.pc = start;
 92→        self.paused = true;
 93→        self.program_end = result.highest_address;
 94→        Ok(result.bytes_loaded)
 95→    }
 96→
 97→    /// Load assembled bytes into memory at given address
 98→    pub fn load_program(&mut self, addr: u32, bytes: &[u8]) {
 99→        self.cpu.load_program(addr, bytes);
100→        let end = addr + bytes.len() as u32;
101→        if end > self.program_end {
102→            self.program_end = end;
103→        }
104→    }
105→
106→    /// Set the program extent (highest address used by program code)
107→    pub fn load_program_extent(&mut self, end: u32) {
108→        if end > self.program_end {
109→            self.program_end = end;
110→        }
111→    }
112→
113→    /// Reset CPU (preserves memory)
114→    pub fn reset(&mut self) {
115→        self.cpu.reset();
116→        self.paused = true;
117→    }
118→
119→    /// Hard reset (clears memory too)
120→    pub fn hard_reset(&mut self) {
121→        self.cpu.hard_reset();
122→        self.paused = true;
123→    }
124→
125→    // ===== Run control =====
126→
127→    /// Run a batch of instructions. Returns what happened.
128→    pub fn run_batch(&mut self, max_instructions: u64) -> BatchResult {
129→        let uart_before = self.cpu.io.uart_output.len();
130→        let led_before = self.cpu.io.leds;
131→        let mut count = 0u64;
132→
133→        if self.cpu.halted {
134→            return BatchResult {
135→                instructions_run: 0,
136→                reason: StopReason::Halted,
137→                uart_bytes_added: 0,
138→                led_changed: false,
139→            };
140→        }
141→
142→        if self.paused {
143→            return BatchResult {
144→                instructions_run: 0,
145→                reason: StopReason::Paused,
146→                uart_bytes_added: 0,
147→                led_changed: false,
148→            };
149→        }
150→
151→        let reason = loop {
152→            if count >= max_instructions {
153→                break StopReason::CycleLimit;
154→            }
155→
156→            // Check breakpoints (skip on first instruction to allow continuing past one)
157→            if count > 0 && self.breakpoints.contains(&self.cpu.pc) {
158→                self.paused = true;
159→                break StopReason::Breakpoint(self.cpu.pc);
160→            }
161→
162→            match self.executor.step(&mut self.cpu) {
163→                ExecuteResult::Ok => {}
164→                ExecuteResult::Halted => {
165→                    break StopReason::Halted;
166→                }
167→                ExecuteResult::InvalidInstruction(byte) => {
168→                    self.cpu.halted = true;
169→                    break StopReason::InvalidInstruction(byte);
170→                }
171→                ExecuteResult::MemoryError(_) => {
172→                    self.cpu.halted = true;
173→                    break StopReason::Halted;
174→                }
175→            }
176→            count += 1;
177→        };
178→
179→        BatchResult {
180→            instructions_run: count,
181→            reason,
182→            uart_bytes_added: self.cpu.io.uart_output.len() - uart_before,
183→            led_changed: self.cpu.io.leds != led_before,
184→        }
185→    }
186→
187→    /// Execute exactly one instruction
188→    pub fn step(&mut self) -> BatchResult {
189→        self.paused = false;
190→        let result = self.run_batch(1);
191→        self.paused = true;
192→        result
193→    }
194→
195→    /// Step over: execute one instruction, but if it's a jal (call),
196→    /// run until return (matching stack depth)
197→    pub fn step_over(&mut self) -> BatchResult {
198→        let inst_byte = self.cpu.read_byte(self.cpu.pc);
199→        let decoded = self.decode_rom.decode(inst_byte);
200→        let is_call = if decoded != 0xFFF {
201→            let inst = DecodedInstruction::from_decoded(decoded);
202→            inst.opcode == Opcode::Jal
203→        } else {
204→            false
205→        };
206→
207→        if !is_call {
208→            return self.step();
209→        }
210→
211→        // It's a call — set a temporary breakpoint after the instruction
212→        let return_addr = self.cpu.pc + 1; // jal is 1 byte
213→        let had_bp = self.breakpoints.contains(&return_addr);
214→        if !had_bp {
215→            self.breakpoints.push(return_addr);
216→        }
217→        self.paused = false;
218→        let result = self.run_batch(10_000_000);
219→        if !had_bp {
220→            self.breakpoints.retain(|&a| a != return_addr);
221→        }
222→        self.paused = true;
223→        result
224→    }
225→
226→    /// Start running (unpause)
227→    pub fn resume(&mut self) {
228→        self.paused = false;
229→    }
230→
231→    /// Pause execution
232→    pub fn pause(&mut self) {
233→        self.paused = true;
234→    }
235→
236→    pub fn is_paused(&self) -> bool {
237→        self.paused
238→    }
239→
240→    pub fn is_halted(&self) -> bool {
241→        self.cpu.halted
242→    }
243→
244→    pub fn is_interrupt_in_service(&self) -> bool {
245→        self.cpu.intis
246→    }
247→
248→    pub fn is_running(&self) -> bool {
249→        !self.paused && !self.cpu.halted
250→    }
251→
252→    // ===== Breakpoints =====
253→
254→    pub fn add_breakpoint(&mut self, addr: u32) -> bool {
255→        if self.breakpoints.contains(&addr) {
256→            false
257→        } else {
258→            self.breakpoints.push(addr);
259→            true
260→        }
261→    }
262→
263→    pub fn remove_breakpoint(&mut self, addr: u32) -> bool {
264→        let len = self.breakpoints.len();
265→        self.breakpoints.retain(|&a| a != addr);
266→        self.breakpoints.len() < len
267→    }
268→
269→    pub fn remove_breakpoint_by_index(&mut self, index: usize) -> Option<u32> {
270→        if index < self.breakpoints.len() {
271→            Some(self.breakpoints.remove(index))
272→        } else {
273→            None
274→        }
275→    }
276→
277→    pub fn clear_breakpoints(&mut self) {
278→        self.breakpoints.clear();
279→    }
280→
281→    pub fn breakpoints(&self) -> &[u32] {
282→        &self.breakpoints
283→    }
284→
285→    pub fn has_breakpoint(&self, addr: u32) -> bool {
286→        self.breakpoints.contains(&addr)
287→    }
288→
289→    // ===== State queries =====
290→
291→    pub fn snapshot(&self) -> CpuSnapshot {
292→        CpuSnapshot {
293→            regs: [
294→                self.cpu.get_reg(0),
295→                self.cpu.get_reg(1),
296→                self.cpu.get_reg(2),
297→                self.cpu.get_reg(3),
298→                self.cpu.get_reg(4),
299→                self.cpu.get_reg(5),
300→                self.cpu.get_reg(6),
301→                self.cpu.get_reg(7),
302→            ],
303→            pc: self.cpu.pc,
304→            c: self.cpu.c,
305→            halted: self.cpu.halted,
306→            intis: self.cpu.intis,
307→            cycles: self.cpu.cycles,
308→            instructions: self.cpu.instructions,
309→            led: self.cpu.io.leds,
310→            button: self.cpu.io.switches,
311→            uart_output_len: self.cpu.io.uart_output.len(),
312→        }
313→    }
314→
315→    pub fn pc(&self) -> u32 {
316→        self.cpu.pc
317→    }
318→
319→    pub fn set_pc(&mut self, pc: u32) {
320→        self.cpu.pc = pc;
321→    }
322→
323→    pub fn get_reg(&self, reg: u8) -> u32 {
324→        self.cpu.get_reg(reg)
325→    }
326→
327→    pub fn set_reg(&mut self, reg: u8, value: u32) {
328→        self.cpu.set_reg(reg, value);
329→    }
330→
331→    pub fn condition_flag(&self) -> bool {
332→        self.cpu.c
333→    }
334→
335→    pub fn cycles(&self) -> u64 {
336→        self.cpu.cycles
337→    }
338→
339→    /// Highest address written during load (end of code+data region)
340→    pub fn program_end(&self) -> u32 {
341→        self.program_end
342→    }
343→
344→    pub fn instructions_count(&self) -> u64 {
345→        self.cpu.instructions
346→    }
347→
348→    // ===== Memory access =====
349→
350→    pub fn read_byte(&self, addr: u32) -> u8 {
351→        self.cpu.read_byte(addr)
352→    }
353→
354→    pub fn write_byte(&mut self, addr: u32, value: u8) {
355→        self.cpu.write_byte(addr, value);
356→    }
357→
358→    pub fn read_word(&self, addr: u32) -> u32 {
359→        self.cpu.read_word(addr)
360→    }
361→
362→    pub fn read_memory(&self, addr: u32, len: u32) -> Vec<u8> {
363→        (0..len).map(|i| self.cpu.read_byte(addr + i)).collect()
364→    }
365→
366→    /// Direct read-only access to SRAM backing memory (0x000000-0x0FFFFF)
367→    pub fn sram(&self) -> &[u8] {
368→        &self.cpu.memory
369→    }
370→
371→    /// Direct read-only access to EBR backing memory (0xFEE000-0xFEFFFF)
372→    pub fn ebr(&self) -> &[u8] {
373→        &self.cpu.ebr
374→    }
375→
376→    // ===== I/O: LED and Button =====
377→
378→    pub fn get_led(&self) -> u8 {
379→        self.cpu.io.leds
380→    }
381→
382→    pub fn get_button(&self) -> bool {
383→        // Button S2: bit 0, normally high, low = pressed
384→        self.cpu.io.switches & 1 == 0
385→    }
386→
387→    pub fn set_button_pressed(&mut self, pressed: bool) {
388→        if pressed {
389→            self.cpu.io.switches &= !1; // low = pressed
390→        } else {
391→            self.cpu.io.switches |= 1; // high = released
392→        }
393→    }
394→
395→    // ===== I/O: UART =====
396→
397→    pub fn get_uart_output(&self) -> &str {
398→        &self.cpu.io.uart_output
399→    }
400→
401→    pub fn clear_uart_output(&mut self) {
402→        self.cpu.io.uart_output.clear();
403→    }
404→
405→    pub fn send_uart_byte(&mut self, byte: u8) {
406→        self.cpu.uart_send_rx(byte);
407→    }
408→
409→    // ===== Trace =====
410→
411→    /// Get the instruction trace buffer
412→    pub fn trace(&self) -> &crate::cpu::state::TraceBuffer {
413→        &self.cpu.trace
414→    }
415→
416→    /// Set UART TX never-ready mode (for testing poll-before-write discipline)
417→    pub fn set_uart_never_ready(&mut self, never_ready: bool) {
418→        self.cpu.io.uart_never_ready = never_ready;
419→        if never_ready {
420→            self.cpu.io.uart_tx_busy = true;
421→        }
422→    }
423→
424→    // ===== Disassembly =====
425→
426→    /// Disassemble one instruction at the given address.
427→    /// Returns (mnemonic_string, instruction_size_in_bytes).
428→    pub fn disassemble_at(&self, addr: u32) -> (String, u32) {
429→        use crate::cpu::instruction::{reg_name, InstructionFormat};
430→
431→        let inst_byte = self.cpu.read_byte(addr);
432→        let decoded = self.decode_rom.decode(inst_byte);
433→        if decoded == 0xFFF {
434→            return (format!(".byte 0x{:02X}", inst_byte), 1);
435→        }
436→
437→        let inst = DecodedInstruction::from_decoded(decoded);
438→        let format = inst.opcode.format();
439→        let size = match format {
440→            InstructionFormat::SingleByte => 1,
441→            InstructionFormat::TwoBytes => 2,
442→            InstructionFormat::FourBytes => 4,
443→        };
444→
445→        let text = match format {
446→            InstructionFormat::SingleByte => match inst.opcode {
447→                Opcode::Pop => format!("pop  {}", reg_name(inst.ra)),
448→                Opcode::Push => format!("push {}", reg_name(inst.ra)),
449→                Opcode::Jmp => format!("jmp  ({})", reg_name(inst.ra)),
450→                Opcode::Jal => {
451→                    format!("jal  {},({})", reg_name(inst.ra), reg_name(inst.rb))
452→                }
453→                Opcode::Mov if inst.rb == 5 => {
454→                    format!("mov  {},c", reg_name(inst.ra))
455→                }
456→                _ => {
457→                    format!(
458→                        "{:4} {},{}",
459→                        inst.opcode.mnemonic(),
460→                        reg_name(inst.ra),
461→                        reg_name(inst.rb)
462→                    )
463→                }
464→            },
465→            InstructionFormat::TwoBytes => {
466→                let imm = self.cpu.read_byte(addr + 1);
467→                let signed = imm as i8;
468→                match inst.opcode {
469→                    Opcode::Bra | Opcode::Brf | Opcode::Brt => {
470→                        let branch_base = addr.wrapping_add(4);
471→                        let target =
472→                            CpuState::mask_24(branch_base.wrapping_add(CpuState::sign_extend_8(imm)));
473→                        format!(
474→                            "{:4} 0x{:06X}",
475→                            inst.opcode.mnemonic(),
476→                            target
477→                        )
478→                    }
479→                    Opcode::Lc | Opcode::Lcu | Opcode::AddImm => {
480→                        format!(
481→                            "{:4} {},{}",
482→                            inst.opcode.mnemonic(),
483→                            reg_name(inst.ra),
484→                            signed
485→                        )
486→                    }
487→                    _ => {
488→                        // Lb, Lbu, Lw, Sb, Sw with offset
489→                        if signed == 0 {
490→                            format!(
491→                                "{:4} {},({})",
492→                                inst.opcode.mnemonic(),
493→                                reg_name(inst.ra),
494→                                reg_name(inst.rb)
495→                            )
496→                        } else {
497→                            format!(
498→                                "{:4} {},{}({})",
499→                                inst.opcode.mnemonic(),
500→                                reg_name(inst.ra),
501→                                signed,
502→                                reg_name(inst.rb)
503→                            )
504→                        }
505→                    }
506→                }
507→            }
508→            InstructionFormat::FourBytes => {
509→                let b0 = self.cpu.read_byte(addr + 1) as u32;
510→                let b1 = self.cpu.read_byte(addr + 2) as u32;
511→                let b2 = self.cpu.read_byte(addr + 3) as u32;
512→                let imm24 = b0 | (b1 << 8) | (b2 << 16);
513→                format!(
514→                    "{:4} {},0x{:06X}",
515→                    inst.opcode.mnemonic(),
516→                    reg_name(inst.ra),
517→                    imm24
518→                )
519→            }
520→        };
521→
522→        (text, size)
523→    }
524→
525→    /// Disassemble N instructions starting at addr
526→    pub fn disassemble(&self, addr: u32, count: usize) -> Vec<(u32, String, u32)> {
527→        let mut result = Vec::with_capacity(count);
528→        let mut pc = addr;
529→        for _ in 0..count {
530→            let (text, size) = self.disassemble_at(pc);
531→            result.push((pc, text, size));
532→            pc = CpuState::mask_24(pc + size);
533→        }
534→        result
535→    }
536→}
