void test_eval_one(char *input, char *expected) {
    int expr = read_str(input);
    int result = eval(expr, NIL_VAL);
    puts_str(input);
    puts_str(" => ");
    print_val(result);
    puts_str(" [");
    puts_str(expected);
    puts_str("]\n");
}

void test_eval() {
    /* Self-evaluating */
    test_eval_one("42", "42");
    test_eval_one("-7", "-7");

